import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

/**
 * Authentication page. Since Firebase has been removed, this page
 * prompts the user for their name and stores it in localStorage.
 * Once a name is provided, the user is considered "logged in" and
 * redirected to the main application. If the user is already
 * authenticated (a valid auth object exists in localStorage), they
 * will be redirected immediately without seeing this form.
 */
export const Auth = () => {
  const [nameInput, setNameInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { isAuth } = useAuth();

  // Redirect authenticated users to the home page
  useEffect(() => {
    if (isAuth) {
      navigate('/app');
    }
  }, [isAuth, navigate]);

  const handleLogin = () => {
    const trimmedName = nameInput.trim();
    setError('');
    if (!trimmedName) {
      setError('Please enter your name');
      return;
    }
    setIsLoading(true);
    setTimeout(() => {
      // Get existing users list or initialize
      let users = [];
      try {
        const storedUsers = localStorage.getItem('budgetbuddy_users');
        users = storedUsers ? JSON.parse(storedUsers) : [];
      } catch (e) {
        users = [];
      }

      // Check if user already exists
      let existingUser = users.find(
        (u) => u.name.toLowerCase() === trimmedName.toLowerCase()
      );
      let authInfo;

      if (existingUser) {
        // User exists, use their existing ID
        authInfo = {
          name: existingUser.name,
          userID: existingUser.userID,
          photo: null,
          isAuth: true,
        };
      } else {
        // New user, create new ID
        const newUserID = Date.now().toString();
        authInfo = {
          name: trimmedName,
          userID: newUserID,
          photo: null,
          isAuth: true,
        };
        // Add to users list
        users.push({
          name: trimmedName,
          userID: newUserID,
          createdAt: new Date().toISOString(),
        });
        localStorage.setItem('budgetbuddy_users', JSON.stringify(users));
      }

      localStorage.setItem('auth', JSON.stringify(authInfo));
      navigate('/app');
    }, 300);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && nameInput.trim()) {
      handleLogin();
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4 bg-gradient-to-br from-slate-950 via-blue-900 to-slate-900 relative overflow-hidden">
      {/* Animated background elements */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-40 -right-40 w-80 h-80 bg-blue-500/10 rounded-full blur-3xl"></div>
        <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-amber-500/10 rounded-full blur-3xl"></div>
        <div className="absolute top-1/2 left-1/2 w-96 h-96 bg-slate-700/5 rounded-full blur-3xl -translate-x-1/2 -translate-y-1/2"></div>
      </div>

      <div className="w-full max-w-sm relative z-10">
        {/* Glowing card container */}
        <div className="relative group">
          {/* Glow effect */}
          <div className="absolute inset-0 bg-gradient-to-r from-blue-500/20 to-amber-500/20 rounded-3xl blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

          {/* Card */}
          <div className="relative bg-slate-900/90 backdrop-blur-xl rounded-3xl shadow-2xl overflow-hidden border border-blue-500/20 hover:border-blue-500/40 transition-all duration-300">
            {/* Gradient top accent */}
            <div className="h-1 bg-gradient-to-r from-blue-500 via-amber-500 to-blue-500"></div>

            <div className="px-8 pt-12 pb-8">
              {/* Logo container */}
              <div className="flex justify-center mb-6">
                <div className="relative">
                  <div className="absolute inset-0 bg-gradient-to-br from-blue-500/50 to-amber-500/50 rounded-2xl blur-lg"></div>
                  <div className="relative w-16 h-16 rounded-2xl bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-3xl shadow-xl">
                    💰
                  </div>
                </div>
              </div>

              {/* Header text */}
              <div className="text-center mb-8">
                <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-300 via-blue-100 to-amber-300 bg-clip-text text-transparent mb-2">
                  Budget Buddy
                </h1>
                <p className="text-blue-200/70 text-sm font-medium">Master your finances with elegance</p>
              </div>

              {/* Form */}
              <div className="space-y-5">
                <div>
                  <label className="block text-sm font-semibold text-blue-200 mb-3">
                    Your Name
                  </label>
                  <input
                    type="text"
                    placeholder="John Doe"
                    value={nameInput}
                    onChange={(e) => {
                      setNameInput(e.target.value);
                      setError('');
                    }}
                    onKeyPress={handleKeyPress}
                    disabled={isLoading}
                    className="w-full px-4 py-3 rounded-xl border-2 border-blue-500/30 focus:border-blue-400 focus:outline-none transition-all duration-200 bg-slate-800/50 focus:bg-slate-800 text-slate-100 placeholder-slate-400 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg focus:shadow-blue-500/20 focus:shadow-lg backdrop-blur-sm"
                  />
                  {error && (
                    <p className="text-amber-400 text-sm mt-2 font-medium">{error}</p>
                  )}
                </div>

                <button
                  onClick={handleLogin}
                  disabled={isLoading || !nameInput.trim()}
                  className="w-full bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-500 hover:to-blue-600 disabled:from-slate-600 disabled:to-slate-700 text-white font-bold py-3 px-4 rounded-xl transition-all duration-300 transform hover:scale-105 hover:shadow-lg hover:shadow-blue-500/50 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none shadow-lg relative overflow-hidden group/btn"
                >
                  <span className="relative z-10 flex items-center justify-center gap-2">
                    {isLoading ? (
                      <>
                        <span className="animate-spin">✨</span>
                        Signing in...
                      </>
                    ) : (
                      <>
                        Let's Get Started
                        <span className="text-lg">→</span>
                      </>
                    )}
                  </span>
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover/btn:translate-x-full transition-transform duration-700"></div>
                </button>
              </div>

              {/* Divider */}
              <div className="my-6 flex items-center gap-3">
                <div className="flex-1 h-px bg-gradient-to-r from-transparent to-blue-500/30"></div>
                <span className="text-xs text-blue-300/60 font-medium">OR</span>
                <div className="flex-1 h-px bg-gradient-to-l from-transparent to-blue-500/30"></div>
              </div>

              {/* Features */}
              <div className="space-y-3">
                <div className="flex items-start gap-3 text-sm text-blue-200/80 group/feature hover:text-blue-200 transition-colors">
                  <span className="text-amber-400 font-bold mt-0.5">→</span>
                  <span>Track & manage all your expenses</span>
                </div>
                <div className="flex items-start gap-3 text-sm text-blue-200/80 group/feature hover:text-blue-200 transition-colors">
                  <span className="text-amber-400 font-bold mt-0.5">→</span>
                  <span>Get detailed insights on spending</span>
                </div>
                <div className="flex items-start gap-3 text-sm text-blue-200/80 group/feature hover:text-blue-200 transition-colors">
                  <span className="text-amber-400 font-bold mt-0.5">→</span>
                  <span>100% private, data stays with you</span>
                </div>
              </div>
            </div>

            {/* Footer */}
            <div className="px-8 py-4 bg-gradient-to-r from-blue-900/30 to-slate-900/30 border-t border-blue-500/10 backdrop-blur-sm">
              <p className="text-center text-xs text-blue-300/60">
                No account • No login • Just pure budgeting
              </p>
            </div>
          </div>
        </div>

        {/* Footer text */}
        <p className="text-center text-sm text-blue-300/60 mt-8 font-medium">
          Start your financial journey today ✨
        </p>
      </div>
    </div>
  );
};
